'{\"before\": {\"id\": \"8d5405c2-d1d2-40e7-9abb-5b434ccf0ef1\", \"type\": \"FORMAL\", \"scope\": \"????\", \"title\": \"???????\", \"result\": \"PENDING\", \"status\": \"DRAFT\", \"endedAt\": null, \"options\": [{\"id\": \"8eb66bd2-d45b-4d76-bc5d-e77851352267\", \"sortNo\": 1, \"optionText\": \"??\"}, {\"id\": \"860d3a21-ea0b-4bb8-8e5b-fceaa181ad54\", \"sortNo\": 2, \"optionText\": \"???\"}, {\"id\": \"006a720c-8bd0-420e-9ac8-2f978756dcd5\", \"sortNo\": 3, \"optionText\": \"??\"}], \"sponsor\": \"????\", \"deadline\": \"2026-03-31T00:00:00.000Z\", \"passRate\": 0, \"createdAt\": \"2026-03-21T02:41:16.984Z\", \"updatedAt\": \"2026-03-21T02:41:16.984Z\", \"description\": \"????????\", \"publishedAt\": null, \"totalHouseholds\": 10, \"participantCount\": 0, \"participationRate\": 0}}','::ffff:127.0.0.1','Mozilla/5.0 (Windows NT; Windows NT 10.0; zh-CN) WindowsPowerShell/5.1.19041.3031','2026-03-21 02:41:17.024','admin@example.com','???????'),('04efd6c4-1952-43e3-b25b-9b445f2ad826','ADMIN',NULL,NULL,'PUBLISH','DISCLOSURE_CONTENT','61c595fd-f47d-4b81-901d-554e71fd47fc','{\"after\": {\"id\": \"61c595fd-f47d-4b81-901d-554e71fd47fc\", \"title\": \"关于对和景苑小区实施应急管理的通知\", \"status\": \"PUBLISHED\", \"content\": \"全体业主:\\n因瑞真物业服务企业已退出和景苑小区物业服务项目，经多方公开招聘，日前暂无新的物业服务企业承接本小区物业服务工作。小区公共区域保洁、秩序维护、电梯运行、公共设施设备保障等基础物业服务已处于中断状态，严重影响全休业主正常居住生活，危及小区公共安全与整体管理秩序。\\n为切实保障小区基本运转，维护全体业主生命财产安全与社区和谐稳定，依据《安徽省物业管理条例》第六十七条相关规定，由王福社区对和景苑小区实施应急管理，保障小区基础物业服务持续供给。应急管理期间所产生的保洁、安保、电梯维保、公共设施维修等各项合理费用，由和景苑小区全体业主共同承担。社区后续将安排工作人员统一收取应急管理费用，具体收费标准、费用明细及收缴方式将另行公示，全程接受全体业主监督。应急管理期间，若成功选聘出新的物业服务企业，应急管理工作将自动终止，社区将及时做好物业服务交接工作。请全体业主予以充分理解、大力支持与积极配合，共同维护小区正常生活秩序与居住环境。\\n特此通知。\", \"summary\": null, \"category\": \"通知公告\", \"createdAt\": \"2026-03-21T00:56:14.450Z\", \"publisher\": \"社区办公室\", \"updatedAt\": \"2026-03-21T01:43:29.850Z\", \"publishedAt\": \"2026-03-21T01:43:29.848Z\", \"publishEndAt\": null, \"publishStartAt\": \"2026-03-04T00:00:00.000Z\"}, \"before\": {\"id\": \"61c595fd-f47d-4b81-901d-554e71fd47fc\", \"title\": \"关于对和景苑小区实施应急管理的通知\", \"status\": \"DRAFT\", \"content\": \"全体业主:\\n因瑞真物业服务企业已退出和景苑小区物业服务项目，经多方公开招聘，日前暂无新的物业服务企业承接本小区物业服务工作。小区公共区域保洁、秩序维护、电梯运行、公共设施设备保障等基础物业服务已处于中断状态，严重影响全休业主正常居住生活，危及小区公共安全与整体管理秩序。\\n为切实保障小区基本运转，维护全体业主生命财产安全与社区和谐稳定，依据《安徽省物业管理条例》第六十七条相关规定，由王福社区对和景苑小区实施应急管理，保障小区基础物业服务持续供给。应急管理期间所产生的保洁、安保、电梯维保、公共设施维修等各项合理费用，由和景苑小区全体业主共同承担。社区后续将安排工作人员统一收取应急管理费用，具体收费标准、费用明细及收缴方式将另行公示，全程接受全体业主监督。应急管理期间，若成功选聘出新的物业服务企业，应急管理工作将自动终止，社区将及时做好物业服务交接工作。请全体业主予以充分理解、大力支持与积极配合，共同维护小区正常生活秩序与居住环境。\\n特此通知。\", \"summary\": null, \"category\": \"通知公告\", \"createdAt\": \"2026-03-21T00:56:14.450Z\", \"publisher\": \"社区办公室\", \"updatedAt\": \"2026-03-21T00:57:13.966Z\", \"publishedAt\": null, \"publishEndAt\": null, \"publishStartAt\": \"2026-03-04T00:00:00.000Z\"}}','::ffff:192.168.1.3','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/146.0.0.0 Safari/537.36','2026-03-21 01:43:29.855','admin@example.com','关于对和景苑小区实施应急管理的通知'),('099879a5-bd0b-4f11-95c8-4ede0f2f4138','ADMIN',NULL,NULL,'UPDATE','VOTE','5c83cfce-818b-4f85-bbd2-0a655a5cccc3','{\"after\": {\"id\": \"5c83cfce-818b-4f85-bbd2-0a655a5cccc3\", \"type\": \"FORMAL\", \"scope\": \"1栋业主\", \"title\": \"测试\", \"result\": \"PENDING\", \"status\": \"ONGOING\", \"endedAt\": null, \"options\": [{\"id\": \"c5cffd4c-e0b1-44b4-b3da-ef9d92c98b71\", \"sortNo\": 1, \"optionText\": \"1\"}, {\"id\": \"6df76b2f-c580-42d0-aac3-30d4fd141989\", \"sortNo\": 2, \"optionText\": \"2\"}, {\"id\": \"58c85b19-7678-4025-93fd-54ce4f738839\", \"sortNo\": 3, \"optionText\": \"3\"}], \"sponsor\": \"测试发钱\", \"deadline\": \"2026-03-29T00:00:00.000Z\", \"passRate\": 0, \"createdAt\": \"2026-03-21T03:01:42.820Z\", \"scopeType\": \"BUILDING\", \"updatedAt\": \"2026-03-21T03:40:08.235Z\", \"description\": null, \"publishedAt\": \"2026-03-21T03:36:14.623Z\", \"scopeAudience\": \"OWNER\", \"scopeBuildingId\": \"3101f6b4-802c-4b9d-bfda-4ac6fcf85ae5\", \"totalHouseholds\": 45, \"participantCount\": 0, \"scopeBuildingIds\": [