, \"type\": \"FORMAL\", \"scope\": \"全体业主\", \"title\": \"????????\", \"result\": \"PENDING\", \"status\": \"DRAFT\", \"endedAt\": null, \"options\": [{\"id\": \"80e83ca1-6f39-49ac-8864-b5197ff67c5d\", \"sortNo\": 1, \"optionText\": \"??\"}, {\"id\": \"cc538aa6-95b2-4849-818a-d11953f001ab\", \"sortNo\": 2, \"optionText\": \"???\"}], \"sponsor\": \"????\", \"deadline\": \"2026-03-31T00:00:00.000Z\", \"passRate\": 0, \"createdAt\": \"2026-03-21T02:57:12.576Z\", \"scopeType\": \"ALL\", \"updatedAt\": \"2026-03-21T02:57:12.576Z\", \"description\": null, \"publishedAt\": null, \"scopeAudience\": \"OWNER\", \"scopeBuildingId\": null, \"totalHouseholds\": 0, \"participantCount\": 0, \"participationRate\": 0, \"scopeBuildingName\": null}}','::ffff:127.0.0.1','Mozilla/5.0 (Windows NT; Windows NT 10.0; zh-CN) WindowsPowerShell/5.1.19041.3031','2026-03-21 02:57:12.589','admin@example.com','????????'),('7534b57d-2b55-4f27-928c-9b6bd2de3c16','ADMIN',NULL,NULL,'UPDATE','DISCLOSURE_CONTENT','398a8a4b-6e93-473d-925c-d50eb3a64789','{\"after\": {\"id\": \"398a8a4b-6e93-473d-925c-d50eb3a64789\", \"title\": \"关于和景苑小区应急管理服务及下一步安排告知\", \"status\": \"PUBLISHED\", \"content\": \"各位业主:因小区长期拖欠物业费，多家物业企业先后退出，新物业引进困难目前无正规企业愿意接管。为保障小区基本运转，社区已启动3个月应急管理费代收工作。经统计，目前仅少数业主缴费，多数业主各种理由观望和拒缴，发表不实言论、诋毁网格员等情况，严重影响小区正常管理秩序。根据《安徽省物业管理条例》第六十七条规定，应急物业服务费用由业主承担，居(村)民委员会可组织开展基本保洁、电梯运行等服务当前本栋缴费情况，已无法支撑垃圾清运、电梯维保、二次供水等必要开支。\\n经研究决定:\\n1.下一步将启动退费流程，优先从缴费率及参与度较低的楼栋开始。2.退费后，同步停止本栋电梯维保运行、垃圾清运、公共能耗、二次供水等基础服务。请家中有老人、小孩的业主，提前做好生活安排与\\n应急准备。社区尊重业主自治意愿，现已协助建立业主微信群，搭建沟通议事平台。请全体业主尽快入群共商，推选楼栋长及本栋代表，确定自主管理方案。若全体一致决定不接受应急服务，社区将尊重最终决定，但后\\n续所有生活保障相关责任需由业主自行承担。社区衷心感谢所有主动缴费、积极配合的业主，是大家的担当支撑了小区特殊时期的基本运转。\\n如需继续支持小区应急服务，自愿缴费可通过以下方式:1.微信群内转账给社区工作人员。\\n2.前往南大门临时收费点缴纳请大家收到信息后尽快办理，并相互转告宣传。只有业主们同心协力，社区才有更大信心协助大家引进更优质的物业服务，共同改善居住环境\", \"summary\": \"急管理服务安排告知\", \"category\": \"通知公告\", \"createdAt\": \"2026-03-21T00:54:09.516Z\", \"publisher\": \"王福社区\", \"updatedAt\": \"2026-03-21T02:17:39.850Z\", \"publishedAt\": \"2026-03-21T00:54:15.685Z\", \"publishEndAt\": null, \"publishStartAt\": \"2026-03-15T00:00:00.000Z\"}, \"before\": {\"id\": \"398a8a4b-6e93-473d-925c-d50eb3a64789\", \"title\": \"关于和景苑小区应急管理服务及下一步安排告知\", \"status\": \"PUBLISHED\", \"content\": \"各位业主:因小区长期拖欠物业费，多家物业企业先后退出，新物业引进困难目前无正规企业愿意接管。为保障小区基本运转，社区已启动3个月应急管理费代收工作。经统计，目前仅少数业主缴费，多数业主各种理由观望和拒缴，发表不实言论、诋毁网格员等情况，严重影响小区正常管理秩序。根据《安徽省物业管理条例》第六十七条规定，应急物业服务费用由业主承担，居(村)民委员会可组织开展基本保洁、电梯运行等服务当前本栋缴费情况，已无法支撑垃圾清运、电梯维保、二次供水等必要开支。\\n经研究决定:\\n1.下一步将启动退费流程，优先从缴费率及参与度较低的楼栋开始。2.退费后，同步停止本栋电梯维保运行、垃圾清运、公共能耗、二次供水等基础服务。请家中有老人、小孩的业主，提前做好生活安排与\\n应急准备。社区尊重业主自治意愿，现已协助建立业主微信群，搭建沟通议事平台。请全体业主尽快入群共商，推选楼栋长及本栋代表，确定自主管理方案。若全体一致决定不接受应急服务，社区将尊重最终决定，但后\\n续所有生活保障相关责任需由业主自行承担。社区衷心感谢所有主动缴费、积极配合的业主，是大家的担当支撑了小区特殊时期的基本运转。\\n如需继续支持小区应急服务，自愿缴费可通过以下方式:1.微信群内转账给社区工作人员。\\n2.前往南大门临时收费点缴纳请大家收到信息后尽快办理，并相互转告宣传。只有业主们同心协力，社区才有更大信心协助大家引进更优质的物业服务，共同改善居住环境\", \"summary\": \"急管理服务安排告知\", \"category\": \"通知公告\", \"createdAt\": \"2026-03-21T00:54:09.516Z\", \"publisher\": \"社区办公室\", \"updatedAt\": \"2026-03-21T00:57:01.070Z\", \"publishedAt\": \"2026-03-21T00:54:15.685Z\", \"publishEndAt\": null, \"publishStartAt\": \"2026-03-15T00:00:00.000Z\"}}','::ffff:192.168.1.3','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/146.0.0.0 Safari/537.36','2026-03-21 02:17:39.856','admin@example.com','关于和景苑小区应急管理服务及下一步安排告知'),('78240138-52c2-45bd-9baf-54ffa2934158','ADMIN',NULL,NULL,'DELETE','VOTE','e321ae7d-8c2e-4d2b-8ff2-f9fb100d136a','{\"before\": {\"id\": \"e321ae7d-8c2e-4d2b-8ff2-f9fb100d136a\", \"type\": \"CONSULTATION\", \"scope\": \"1栋、2栋住户\", \"title\": \"???????\", \"result\": \"PENDING\", \"status\": \"DRAFT\", \"endedAt\": null, \"options\": [{\"id\": \"21a620ed-7003-431f-b3a9-2e271bf4d8e9\", \"sortNo\": 1, \"optionText\": \"??\"}, {\"id\": \"ca893207-51d0-46a1-844f-88eddf9e1f2a\", \"sortNo\": 2, \"optionText\": \"??\"}], \"sponsor\": \"????\", \"deadline\": \"2026-03-31T00:00:00.000Z\", \"passRate\": 0, \"createdAt\": \"2026-03-21T03:10:12.088Z\", \"scopeTyp