: \"OWNER\", \"scopeBuildingId\": \"3101f6b4-802c-4b9d-bfda-4ac6fcf85ae5\", \"totalHouseholds\": 45, \"participantCount\": 0, \"scopeBuildingIds\": [\"3101f6b4-802c-4b9d-bfda-4ac6fcf85ae5\"], \"participationRate\": 0, \"scopeBuildingName\": \"1栋\", \"scopeBuildingNames\": [\"1栋\"]}, \"before\": {\"id\": \"5c83cfce-818b-4f85-bbd2-0a655a5cccc3\", \"type\": \"FORMAL\", \"scope\": \"1栋业主\", \"title\": \"测试\", \"result\": \"PASSED\", \"status\": \"ONGOING\", \"endedAt\": null, \"options\": [{\"id\": \"5b3d10e8-94af-48b7-89d4-5081c4bd29e4\", \"sortNo\": 1, \"optionText\": \"1\"}, {\"id\": \"97d788e6-4455-4ceb-9d96-448b642f1995\", \"sortNo\": 2, \"optionText\": \"2\"}, {\"id\": \"03204c64-6005-46ba-a97a-fa037ec737c3\", \"sortNo\": 3, \"optionText\": \"3\"}], \"sponsor\": \"测试发钱\", \"deadline\": \"2026-03-29T00:00:00.000Z\", \"passRate\": 0, \"createdAt\": \"2026-03-21T03:01:42.820Z\", \"scopeType\": \"BUILDING\", \"updatedAt\": \"2026-03-21T03:36:43.235Z\", \"description\": null, \"publishedAt\": \"2026-03-21T03:36:14.623Z\", \"scopeAudience\": \"OWNER\", \"scopeBuildingId\": \"3101f6b4-802c-4b9d-bfda-4ac6fcf85ae5\", \"totalHouseholds\": 45, \"participantCount\": 0, \"scopeBuildingIds\": [\"3101f6b4-802c-4b9d-bfda-4ac6fcf85ae5\"], \"participationRate\": 0, \"scopeBuildingName\": \"1栋\", \"scopeBuildingNames\": [\"1栋\"]}}','::ffff:192.168.1.3','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/146.0.0.0 Safari/537.36','2026-03-21 03:38:28.602','admin@example.com','测试'),('e361c41a-281e-4e14-ba00-4d890da17a9b','ADMIN',NULL,NULL,'UPDATE','DISCLOSURE_CONTENT','61c595fd-f47d-4b81-901d-554e71fd47fc','{\"after\": {\"id\": \"61c595fd-f47d-4b81-901d-554e71fd47fc\", \"title\": \"关于对和景苑小区实施应急管理的通知\", \"status\": \"PUBLISHED\", \"content\": \"全体业主:\\n因瑞真物业服务企业已退出和景苑小区物业服务项目，经多方公开招聘，日前暂无新的物业服务企业承接本小区物业服务工作。小区公共区域保洁、秩序维护、电梯运行、公共设施设备保障等基础物业服务已处于中断状态，严重影响全休业主正常居住生活，危及小区公共安全与整体管理秩序。\\n为切实保障小区基本运转，维护全体业主生命财产安全与社区和谐稳定，依据《安徽省物业管理条例》第六十七条相关规定，由王福社区对和景苑小区实施应急管理，保障小区基础物业服务持续供给。应急管理期间所产生的保洁、安保、电梯维保、公共设施维修等各项合理费用，由和景苑小区全体业主共同承担。社区后续将安排工作人员统一收取应急管理费用，具体收费标准、费用明细及收缴方式将另行公示，全程接受全体业主监督。应急管理期间，若成功选聘出新的物业服务企业，应急管理工作将自动终止，社区将及时做好物业服务交接工作。请全体业主予以充分理解、大力支持与积极配合，共同维护小区正常生活秩序与居住环境。\\n特此通知。\", \"summary\": null, \"category\": \"通知公告\", \"createdAt\": \"2026-03-21T00:56:14.450Z\", \"publisher\": \"王福社区\", \"updatedAt\": \"2026-03-21T02:17:27.228Z\", \"publishedAt\": \"2026-03-21T01:43:29.848Z\", \"publishEndAt\": null, \"publishStartAt\": \"2026-03-04T00:00:00.000Z\"}, \"before\": {\"id\": \"61c595fd-f47d-4b81-901d-554e71fd47fc\", \"title\": \"关于对和景苑小区实施应急管理的通知\", \"status\": \"PUBLISHED\", \"content\": \"全体业主:\\n因瑞真物业服务企业已退出和景苑小区物业服务项目，经多方公开招聘，日前暂无新的物业服务企业承接本小区物业服务工作。小区公共区域保洁、秩序维护、电梯运行、公共设施设备保障等基础物业服务已处于中断状态，严重影响全休业主正常居住生活，危及小区公共安全与整体管理秩序。\\n为切实保障小区基本运转，维护全体业主生命财产安全与社区和谐稳定，依据《安徽省物业管理条例》第六十七条相关规定，由王福社区对和景苑小区实施应急管理，保障小区基础物业服务持续供给。应急管理期间所产生的保洁、安保、电梯维保、公共设施维修等各项合理费用，由和景苑小区全体业主共同承担。社区后续将安排工作人员统一收取应急管理费用，具体收费标准、费用明细及收缴方式将另行公示，全程接受全体业主监督。应急管理期间，若成功选聘出新的物业服务企业，应急管理工作将自动终止，社区将及时做好物业服务交接工作。请全体业主予以充分理解、大力支持与积极配合，共同维护小区正常生活秩序与居住环境。\\n特此通知。\", \"summary\": null, \"category\": \"通知公告\", \"createdAt\": \"2026-03-21T00:56:14.450Z\", \"publisher\": \"社区办公室\", \"updatedAt\": \"2026-03-21T01:43:29.850Z\", \"publishedAt\": \"2026-03-21T01:43:29.848Z\", \"publishEndAt\": null, \"publishStartAt\": \"2026-03-04T00:00:00.000Z\"}}','::ffff:192.168.1.3','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/146.0.0.0 Safari/537.36','2026-03-21 02:17:27.234','admin@example.com','关于对和景苑小区实施应急管理的通知'),('ea2f47e0-6f4f-4ae7-b54a-3b3980776079','ADMIN',NULL,NULL,'DELETE','VOTE','14ee03bc-cbb4-4f62-befb-34134acce376','{\"before\": {\"id\": \"14ee03bc-cbb4-4f62-befb-34134acce376\", \"type\": \"CONSULTATION\", \"scope\": \"1栋住户\", \"title\": \"?????????\", \"result\": \"PENDING\", \"status\": \"DRAFT\", \"endedAt\": null, \"options\": [{\"id\": \"478f6ed4-0b15-42b7-aec7-f2e0216654a8\", \"sortNo\": 1, \"optionText\": \"??\"}, {\"id\": \"