INSERT INTO `disclosure_contents` VALUES ('398a8a4b-6e93-473d-925c-d50eb3a64789','关于和景苑小区应急管理服务及下一步安排告知','通知公告','急管理服务安排告知','各位业主:因小区长期拖欠物业费，多家物业企业先后退出，新物业引进困难目前无正规企业愿意接管。为保障小区基本运转，社区已启动3个月应急管理费代收工作。经统计，目前仅少数业主缴费，多数业主各种理由观望和拒缴，发表不实言论、诋毁网格员等情况，严重影响小区正常管理秩序。根据《安徽省物业管理条例》第六十七条规定，应急物业服务费用由业主承担，居(村)民委员会可组织开展基本保洁、电梯运行等服务当前本栋缴费情况，已无法支撑垃圾清运、电梯维保、二次供水等必要开支。\n经研究决定:\n1.下一步将启动退费流程，优先从缴费率及参与度较低的楼栋开始。2.退费后，同步停止本栋电梯维保运行、垃圾清运、公共能耗、二次供水等基础服务。请家中有老人、小孩的业主，提前做好生活安排与\n应急准备。社区尊重业主自治意愿，现已协助建立业主微信群，搭建沟通议事平台。请全体业主尽快入群共商，推选楼栋长及本栋代表，确定自主管理方案。若全体一致决定不接受应急服务，社区将尊重最终决定，但后\n续所有生活保障相关责任需由业主自行承担。社区衷心感谢所有主动缴费、积极配合的业主，是大家的担当支撑了小区特殊时期的基本运转。\n如需继续支持小区应急服务，自愿缴费可通过以下方式:1.微信群内转账给社区工作人员。\n2.前往南大门临时收费点缴纳请大家收到信息后尽快办理，并相互转告宣传。只有业主们同心协力，社区才有更大信心协助大家引进更优质的物业服务，共同改善居住环境','PUBLISHED','2026-03-15 00:00:00.000',NULL,'2026-03-21 00:54:15.685','2026-03-21 00:54:09.516','2026-03-21 02:17:39.850','王福社区'),('61c595fd-f47d-4b81-901d-554e71fd47fc','关于对和景苑小区实施应急管理的通知','通知公告',NULL,'全体业主:\n因瑞真物业服务企业已退出和景苑小区物业服务项目，经多方公开招聘，日前暂无新的物业服务企业承接本小区物业服务工作。小区公共区域保洁、秩序维护、电梯运行、公共设施设备保障等基础物业服务已处于中断状态，严重影响全休业主正常居住生活，危及小区公共安全与整体管理秩序。\n为切实保障小区基本运转，维护全体业主生命财产安全与社区和谐稳定，依据《安徽省物业管理条例》第六十七条相关规定，由王福社区对和景苑小区实施应急管理，保障小区基础物业服务持续供给。应急管理期间所产生的保洁、安保、电梯维保、公共设施维修等各项合理费用，由和景苑小区全体业主共同承担。社区后续将安排工作人员统一收取应急管理费用，具体收费标准、费用明细及收缴方式将另行公示，全程接受全体业主监督。应急管理期间，若成功选聘出新的物业服务企业，应急管理工作将自动终止，社区将及时做好物业服务交接工作。请全体业主予以充分理解、大力支持与积极配合，共同维护小区正常生活秩序与居住环境。\n特此通知。','PUBLISHED','2026-03-04 00:00:00.000',NULL,'2026-03-21 01:43:29.848','2026-03-21 00:56:14.450','2026-03-21 02:17:27.228','王福社区');
/*!40000 ALTER TABLE `disclosure_contents` ENABLE KEYS */;
UNLOCK TABLES;

